package be.schaubroeck.lpb.rkm.rekenmotor.service.web;

import be.schaubroeck.context.ConfigConstants;
import be.schaubroeck.context.ExecutionContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenActionType;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenActionFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenActionService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MetaRekenFeedback;
import be.schaubroeck.lpb.tools.AbstractProces;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.exception.LockingException;
import be.schaubroeck.lpb.tools.exception.MessageException;
import be.schaubroeck.lpb.tools.exception.ProcesHaltedException;
import be.schaubroeck.lpb.tools.logging.BigProcesLogger;
import be.schaubroeck.temporal.clock.TheClock;
import be.schaubroeck.temporal.util.TemporalContext;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDateTime;

import java.util.concurrent.Future;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicInteger;

@Slf4j
public class RekenProcesImp extends AbstractProces implements RekenProces {

    private static final ThreadLocal<RekenProcesImp> runningProces = new ThreadLocal<>();

    private volatile AtomicBoolean stopFlag = new AtomicBoolean(false);
    private volatile AtomicBoolean stoppedByLock = new AtomicBoolean(false);
    private volatile AtomicBoolean waitingForLock = new AtomicBoolean(false);

    private RekenActionFactory rekenActionFactory;

    private final LocalDateTime creatieTijdstip;
    private LocalDateTime startTijdstip = null;
    private LocalDateTime stopTijdstip = null;

    private RekenActionType type;
    private RekenContext actionParams;
    private Admin admin;
    private String omschrijving;
    private String actor;
    private MetaRekenFeedback feedback = null;

    private final String tenant;

    private Future<?> future;

    public RekenProcesImp(
            Admin admin, String procesId, RekenActionFactory rekenActionFactory, String omschrijving, String actor,
            RekenActionType type, RekenContext actionParams, String tenant) {
        init(procesId);
        this.rekenActionFactory = rekenActionFactory;
        creatieTijdstip = TheClock.getInstance().getNow();
        this.type = type;
        this.actionParams = actionParams;
        this.admin = admin;
        this.omschrijving = omschrijving;
        this.actor = actor;
        this.tenant = tenant;
    }

    @Override
    public void init(String id) {
        this.id = id;
        this.totaal = new AtomicInteger(0);
        this.verwerkt = new AtomicInteger(0);
        this.isDone = new AtomicBoolean(false);
        this.errorCause = null;
    }

    @Override
    public void run() {
        BigProcesLogger bigProcesLogger = new BigProcesLogger();
        bigProcesLogger.start(admin.getId(), "REKENMOTOR", "Berekenen van lonen");
        //making a new executionContext is necessary because new threads inherit the same ExecutionContext object from their parent thread.
        //This can cause serious problems with the database state.(See SimpleStateKeeper)
        ExecutionContext ec = ExecutionContext.newContext();
        ec.setUserAttribute(ConfigConstants.TENANT_EC_ATTR, tenant);
        try {
            startTijdstip = TheClock.getInstance().getNow();
            initRun();
            RekenActionService actionService = rekenActionFactory.bepaal(type);
            feedback = actionService.start(admin, actor, actionParams);
            notifyCentral();
        } catch (ProcesHaltedException exception) {
            String manualStop = "RekenProces werd manueel gestopt.";
            omschrijving = manualStop + " " + omschrijving;
            log.debug(manualStop, exception);
        } catch (LockingException exception) {
            errorCause = exception;
            stoppedByLock.set(true);
            String lockStop = "RekenProces werd gestopt wegens lock.";
            omschrijving = lockStop + " " + omschrijving;
            log.debug(lockStop, exception);
        } catch (Exception e) {
            errorCause = e;
            String exceptionStop = "RekenProces werd gestopt wegens " + e.getClass().getSimpleName();
            omschrijving = exceptionStop + " " + omschrijving;
            log.error(exceptionStop, e);
        } finally {
            stopTijdstip = TheClock.getInstance().getNow();
            isDone.set(true);
            CacheContext.getInstance().clearCachedServices(CacheContext.Scope.ADMIN);
            cleanRun();
            bigProcesLogger.stop(this.getTotaal());
        }
    }

    private void initRun() {
        if (runningProces.get() == null || runningProces.get() == this) {
            runningProces.set(this);
        } else {
            throw new MessageException("Er mag maar een rekenproces lopen per thread");
        }
    }

    public void cleanRun() {
        if (runningProces.get() == this) {
            runningProces.set(null);
        }
        TemporalContext.clear();
    }

    private synchronized void notifyCentral() {

    }

    @Override
    public synchronized void halt() {
        if (future != null) {
            future.cancel(true);
        } else {
            Thread.currentThread().interrupt();
        }
        stopFlag.set(true);
    }

    @Override
    public synchronized void setFuture(Future<?> future) {
        this.future = future;
    }

    @Override
    public boolean getStopFlag() {
        return stopFlag.get();
    }

    @Override
    public boolean getStoppedByLock() {
        return stoppedByLock.get();
    }

    @Override
    public boolean getWaitingForLock() {
        return waitingForLock.get();
    }

    @Override
    public RekenActionType getType() {
        return type;
    }

    @Override
    public RekenContext getActionParams() {
        return actionParams;
    }

    @Override
    public String getActor() {
        return actor;
    }

    @Override
    public int getAdminId() {
        return admin.getId();
    }

    @Override
    public Admin getAdmin() {
        return admin;
    }

    @Override
    public boolean isFinished() {
        return isDone.get();
    }

    @Override
    public boolean hasRekenAtomenNieuweAgendas() {
        return feedback != null && feedback.getAtoomToFeedbackMap().values().stream().anyMatch(o -> o.getAantalArtikelAgendas() > 0 || o.getAantalRegulAgendas() > 0);
    }

    @Override
    public synchronized double getPercentageProgress() {
        double percentage = 0;
        if (totaal.doubleValue() != 0) {
            percentage = Math.round(verwerkt.doubleValue() / totaal.doubleValue() * 10000) / 100;
        }
        //In geval van een faal staat wilen we zien dat de progressbar rood kleurt
        if (percentage < 10 && (isFinished() || getStopFlag())) {
            percentage = 10;
        }
        return percentage;
    }

    public static boolean isInStopState() {
        return runningProces.get() != null && runningProces.get().getStopFlag();
    }

    public static void incrementVerwerktStatic() {
        RekenProcesImp proces = runningProces.get();
        if (proces != null) {
            proces.verwerkt.incrementAndGet();
        }
    }

    public static void setTotaalStatic(int totaal) {
        RekenProcesImp proces = runningProces.get();
        if (proces != null) {
            proces.totaal = new AtomicInteger(totaal);
        }
    }

    public static void resetVerwerkt() {
        RekenProcesImp proces = runningProces.get();
        if (proces != null) {
            proces.verwerkt = new AtomicInteger(0);
        }
    }

    public static void setStatusWaitingForLockStatic() {
        runningProces.get().setStatusWaitingForLock();
    }

    private void setStatusWaitingForLock() {
        if (totaal.intValue() == 0 && verwerkt.intValue() == 0) {
            totaal.set(1);
            verwerkt.set(1);
        }
        waitingForLock.set(true);
        String lockStop = "Waiting for Lock";
        omschrijving = lockStop + " " + omschrijving;
    }

    @Override
    public LocalDateTime getTimeCreation() {
        return this.creatieTijdstip;
    }

    @Override
    public LocalDateTime getTimeStarted() {
        return this.startTijdstip;
    }

    @Override
    public LocalDateTime getTimeEnded() {
        return this.stopTijdstip;
    }

    @Override
    public boolean isDone() {
        return isDone.get();
    }

    @Override
    public String getOmschrijving() {
        return omschrijving;
    }

    @Override
    public String getTenant() {
        return tenant;
    }

    @Override
    public MetaRekenFeedback getFeedback() {
        return feedback;
    }
}
